document.addEventListener('DOMContentLoaded',function(){var e=document.querySelector('.nav-hamburger'),n=document.getElementById('nav-menu');if(e&&n){e.addEventListener('click',function(){var o=n.classList.toggle('nav-open');e.setAttribute('aria-expanded',o)});n.querySelectorAll('a').forEach(function(a){a.addEventListener('click',function(){n.classList.remove('nav-open');e.setAttribute('aria-expanded','false')})})}});